sql:
SELECT name, date_of_birth, contact_number 
FROM trainers 
ORDER BY date_of_birth;

SELECT DISTINCT T2.name
FROM horses AS T1
INNER JOIN trainers AS T2 ON T1.trainer_id = T2.trainer_id;

external_knowledge:
- 'types' refers to the breed of the horses;
- 'finishing spots' refer to the position the horse finished in during the race;
- 'rewards' are synonymous with the prize money awarded to the horse based on its performance.

sql:
SELECT h.name, h.breed, h.age, r.position, r.prize_money
FROM horses h
INNER JOIN race_results r ON h.horse_id = r.horse_id;

SELECT vet_id, COUNT(horse_id) AS total_horses
FROM horses
GROUP BY vet_id;

external_knowledge:
- 'sailors' refers to users placing bets;
- 'voyages through the tumultuous sea of bets' refers to the total number of bets placed;
- 'treasures' refers to bets won;
- 'storms' refers to bets lost;
- 'ratio of their successful voyages to the total voyages' refers to the win rate.

sql:
SELECT COUNT(*)
FROM horses
WHERE age > 5;

SELECT name
FROM trainers
WHERE experience_level = 'expert';

SELECT h.name, h.gender
FROM horses h
INNER JOIN race_entries re ON h.horse_id = re.horse_id;

SELECT COUNT(*)
FROM jockeys
WHERE strftime('%Y', 'now') - strftime('%Y', date_of_birth) > 50;

SELECT race_id, COUNT(horse_id) AS total_horses
FROM race_entries
GROUP BY race_id;

SELECT DISTINCT h.name
FROM horses h
JOIN race_entries re ON h.horse_id = re.horse_id;

SELECT type_name, average_speed
FROM race_types
WHERE average_speed > 40;

